static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    VanillaRnnHiddenCustomTilingData tiling;

    // x: [T,B,I]
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *h0_shape = context->GetInputShape(1);
    const gert::Shape *w_i2h_shape = context->GetInputShape(2);
    const gert::Shape *w_h2o_shape = context->GetInputShape(4);

    if (x_shape->GetOriginShape().GetDimNum() != 3 ||
        h0_shape->GetOriginShape().GetDimNum() != 2 ||
        w_i2h_shape->GetOriginShape().GetDimNum() != 2 ||
        w_h2o_shape->GetOriginShape().GetDimNum() != 2) {
        return ge::GRAPH_FAILED;
    }

    const uint64_t T = x_shape->GetOriginShape().GetDim(0);
    const uint64_t B = x_shape->GetOriginShape().GetDim(1);
    const uint64_t I = x_shape->GetOriginShape().GetDim(2);
    const uint64_t H = h0_shape->GetOriginShape().GetDim(1);
    const uint64_t O = w_h2o_shape->GetOriginShape().GetDim(0);

    uint32_t blockDim = static_cast<uint32_t>(B);
    if (blockDim == 0) blockDim = 1;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    tiling.set_T(static_cast<uint32_t>(T));
    tiling.set_B(static_cast<uint32_t>(B));
    tiling.set_I(static_cast<uint32_t>(I));
    tiling.set_H(static_cast<uint32_t>(H));
    tiling.set_O(static_cast<uint32_t>(O));
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspaceSizes = context->GetWorkspaceSizes(1);
    workspaceSizes[0] = 0;

    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

